// Checkbox helper functions
function toggleAllCheckboxes(masterCheckbox) {
  const agreementItem = masterCheckbox.closest(".agreement-item");
  if (!agreementItem) return;
  const individualCheckboxes = agreementItem.querySelectorAll(".individual-check");
  individualCheckboxes.forEach(cb => cb.checked = masterCheckbox.checked);
  checkAllCheckboxes();
}

function checkAllCheckboxes() {
  // Check if all required checkboxes are ticked
  const allCheckboxes = document.querySelectorAll(".agreement-item.expanded .individual-check, .agreement-item.expanded .master-check");
  const acceptanceRadio = document.querySelector(".agreement-item.expanded .acceptance-radio:checked");
  const allChecked = Array.from(allCheckboxes).every(cb => cb.checked) && acceptanceRadio && acceptanceRadio.value === "ya";
  
  // Enable/disable submit button
  const agreementItem = document.querySelector(".agreement-item.expanded");
  if (agreementItem) {
    const submitBtn = agreementItem.querySelector(".btn-submit-single");
    if (submitBtn) {
      submitBtn.disabled = !allChecked;
      if (allChecked) {
        submitBtn.classList.remove("disabled");
      } else {
        submitBtn.classList.add("disabled");
      }
    }
  }
}
